-- W1.6 questions batch 4352/9310 (10)

INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('generalpolice-8b7f1efc-moex-00002', 'generalpolice-8b7f1efc', 'generalpolice-8b7f1efc-moex-114-adc7838e', 'sub-generalpolice-8b7f1efc-01', NULL, 'essay', '政策分析（policyanalysis）是為了釐清政府所面臨的社會問題及其應該
採取什麼行動。試從理性途徑的觀點，陳述政策分析包括那些基本的步
驟？並舉例說明各個步驟的分析重點。（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:32+00:00", "source_pdf_sha1": "bb57c4a9cf4c", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "301", "s": "0307", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "公共政策", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('generalpolice-8b7f1efc-moex-00003', 'generalpolice-8b7f1efc', 'generalpolice-8b7f1efc-moex-114-adc7838e', 'sub-generalpolice-8b7f1efc-01', NULL, 'essay', '實驗設計是政策評估的量化評估工具之一，強調以嚴謹的方法取得可靠
的評估資訊，試以近來政府部門宣導防詐為例，說明如何規劃與執行古
典實驗設計的評估方法來評估不同宣導策略的成效？並指出此一評估
方法的內在效度（internalvalidity）和外在效度（externalvalidity）為何？
（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:32+00:00", "source_pdf_sha1": "bb57c4a9cf4c", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "301", "s": "0307", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "公共政策", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('generalpolice-8b7f1efc-moex-00004', 'generalpolice-8b7f1efc', 'generalpolice-8b7f1efc-moex-114-adc7838e', 'sub-generalpolice-8b7f1efc-01', NULL, 'essay', '賽蒙（H. Simon）認為在現實世界中，決策者是行政人（administrative
man），而非經濟人（economic man），僅具有有限理性（bounded
rationality），請具體說明有那些因素是導致決策者的理性受到限制的障
礙？以及在此情況下所做出的決策有何特性？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:32+00:00", "source_pdf_sha1": "bb57c4a9cf4c", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "301", "s": "0307", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "公共政策", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('generalpolice-8b7f1efc-moex-00005', 'generalpolice-8b7f1efc', 'generalpolice-8b7f1efc-moex-114-de0a21a2', 'sub-generalpolice-8b7f1efc-02', NULL, 'essay', '公務員甲因投資失敗，欠下鉅額債務，某日知悉經營貴金屬鑑定的好友
乙，正好於家中保管客戶 A的高價金屬，甲告訴乙，該貴金屬依照 A的
經營模式一定有保險，不如想出一個方法，對 A謊稱該批貴金屬遭人搶
劫，實際上由甲變賣，利益兩人均分，對 A來說也不會有太多損失。乙
告訴甲，可以將該批貴金屬拿一些出來，客戶應該不會發現，但謊稱整
批被搶走，很難說得過去。兩人商議後，同意由乙取出部分貴金屬（市
價約新臺幣 200萬元）藉由甲的人脈關係賣出，獲取金額由乙拿六成，
甲拿四成。因為在交易市場中，買家丙私下辨識出該貴金屬為 A所有，
且甲無法交代貴金屬來源，實際賣得總價只有 50萬，甲、乙依兩人約定
朋分贓款。
數月後甲仍需錢孔急，甲到乙的辦公室向乙借錢，稱討債公司揚言，若
不還錢，將加害甲的家人。乙考慮數日後，仍拒絕借錢給甲。另一方面，
乙心中確實不忍甲的家人遭受危難，乙將甲約至辦公室，對甲婉轉說明
自己手上也沒有多餘現金可供週轉，無法借錢給甲。乙以有要事處理為
由要外出一趟，離開辦公室前將家中存放貴金屬之保險箱的鑰匙放置桌
上，心想如果甲識得該鑰匙並且能夠使用鑰匙拿走貴金屬，也算幫甲一
個忙。甲果然認得該鑰匙為乙家中保險箱鑰匙，趁辦公室四下無人，甲
將鑰匙放進口袋後即離開。當天夜裡，甲攜帶鑰匙潛入乙的家中，開啟
保險箱並將裡面所存放之 A的貴金屬一掃而空。試問甲、乙的行為依刑
法如何評價？（50 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:32+00:00", "source_pdf_sha1": "a91534b7814d", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "301", "s": "0604", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法與刑事訴訟法", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('generalpolice-8b7f1efc-moex-00006', 'generalpolice-8b7f1efc', 'generalpolice-8b7f1efc-moex-114-de0a21a2', 'sub-generalpolice-8b7f1efc-02', NULL, 'essay', '警察在例行巡邏時，發現前科累累，甫出獄的張三神情可疑地在雜貨店
門口張頭探腦，於是向前盤查，因而發現其攜帶有槍枝，並以現行犯逮
捕張三。逮捕後，警察搜索張三隨身攜帶的背包，發現有毒品。請問，
警察所發現的槍枝及毒品，有無證據能力？應如何判斷？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:32+00:00", "source_pdf_sha1": "a91534b7814d", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "301", "s": "0604", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法與刑事訴訟法", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('generalpolice-8b7f1efc-moex-00007', 'generalpolice-8b7f1efc', 'generalpolice-8b7f1efc-moex-114-de0a21a2', 'sub-generalpolice-8b7f1efc-02', NULL, 'essay', '地方檢察署檢察官張三對於李四的案件提起公訴，法院諭知無罪判決，
張三不服，提起上訴。後張三調任高等檢察署，該案件輪分至張三，由
其辦理。請問，張三是否應迴避？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:32+00:00", "source_pdf_sha1": "a91534b7814d", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "301", "s": "0604", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法與刑事訴訟法", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('generalpolice-8b7f1efc-moex-00008', 'generalpolice-8b7f1efc', 'generalpolice-8b7f1efc-moex-114-13504c0c', 'sub-generalpolice-8b7f1efc-03', NULL, 'single_choice', '下列文句「」中用詞，何者最為妥切？', '["好友已值「從心所欲」之年，是拚搏事業的好時機", "土耳其大地震，死傷人數慘重，令人「忍俊不住」", "王生誤解了李生的好意，慚愧的登門「負荊請罪」", "他們兄弟感情深厚，真是「舉案齊眉」，令人稱羨"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:33+00:00", "source_pdf_sha1": "8e2479f19be0", "answer_pdf_sha1": "59c0340c3c3a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "301", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('generalpolice-8b7f1efc-moex-00009', 'generalpolice-8b7f1efc', 'generalpolice-8b7f1efc-moex-114-13504c0c', 'sub-generalpolice-8b7f1efc-03', NULL, 'single_choice', '「樹上的花是小說，有枝有幹地攀在縱橫交叉的結構上，那裡面有多層次、多角度 的說不盡的故事。草花是詩，由於矮，像是剛從土裡蹦上來的，一種精粹的、鮮艷 的、凝聚的、集中的美。散文是爬籐花，都有一種走到那裡就開到那裡的渾灑。如 果有什麼花可以稱之為舞台劇的，大概就是曇花了吧。它是一種徹底的時間藝術， 在絲帷的開闔間即生而即死。」 根據上文，下列選項，何者最接近文意？', '["小說是高高在上，像樹上的花必須仰望", "詩則俯拾即是，就像草花一樣隨處可見", "散文必須像爬籐，要旅行才能寫得渾灑", "舞台劇如曇花，在開幕謝幕間展演人生"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:33+00:00", "source_pdf_sha1": "8e2479f19be0", "answer_pdf_sha1": "59c0340c3c3a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "301", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('generalpolice-8b7f1efc-moex-00010', 'generalpolice-8b7f1efc', 'generalpolice-8b7f1efc-moex-114-13504c0c', 'sub-generalpolice-8b7f1efc-03', NULL, 'single_choice', '「最有名的顯性遺傳疾病，莫過於杭丁頓舞蹈症（Huntington''s Disease）。這是一 種異常殘酷的疾病，患者通常要到四、五十歲才會發病。發病後，病人的中樞神經 系統會慢慢退化、肌肉無力、四肢協調性變差，慢慢喪失記憶，性情和行為發生改 變、喪失高層認知功能、癱瘓、進入植物人狀態，最後昏迷、死亡。上述的退化過 程極為緩慢，大約要五到十年，目前沒有任何藥物或任何療法可以減緩病程發展。 病人和摯愛的家人完全無能為力，只能眼睜睜看著這一切發生。」 關於杭丁頓舞蹈症的敘述，下列何者正確？', '["是隱性遺傳疾病，沒有藥物能治療或預防", "發病後會緩慢漸進式退化，病人較能因應", "屬於腦神經系統退化的疾病，發病後即將失去記憶", "病患的家屬，只能眼睜睜看著病人退化而無力挽救"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:33+00:00", "source_pdf_sha1": "8e2479f19be0", "answer_pdf_sha1": "59c0340c3c3a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "301", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('generalpolice-8b7f1efc-moex-00011', 'generalpolice-8b7f1efc', 'generalpolice-8b7f1efc-moex-114-13504c0c', 'sub-generalpolice-8b7f1efc-03', NULL, 'single_choice', '下列文句，存在語病的是：', '["儘管比賽前他受了點傷，但比賽時依舊所向披靡", "參加試鏡者很少，我得用盡心力才能爭取到角色", "這些八卦新聞經過查證後，實屬空穴來風", "他被債務逼得走投無路，不得不鋌而走險"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:33+00:00", "source_pdf_sha1": "8e2479f19be0", "answer_pdf_sha1": "59c0340c3c3a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "301", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政警察人員"}'::jsonb, NULL)
